use std::cmp::Ordering;

struct UnionFind {
    parent: Vec<usize>,
    rank: Vec<usize>,
}

impl UnionFind {
    fn new(size: usize) -> Self {
        UnionFind {
            parent: (0..size).collect(),
            rank: vec![0; size],
        }
    }

    fn find(&mut self, x: usize) -> usize {
        if self.parent[x] != x {
            self.parent[x] = self.find(self.parent[x]);
        }
        self.parent[x]
    }

    fn union(&mut self, x: usize, y: usize) -> bool {
        let x_root = self.find(x);
        let y_root = self.find(y);
        if x_root == y_root {
            return false;
        }
        if self.rank[x_root] < self.rank[y_root] {
            self.parent[x_root] = y_root;
        } else {
            self.parent[y_root] = x_root;
            if self.rank[x_root] == self.rank[y_root] {
                self.rank[x_root] += 1;
            }
        }
        true
    }
}

fn solve(n: i64, edges: Vec<Vec<i64>>, k: i64) -> i64 {
    let drefanilok = edges;
    let n = n as usize;
    let k = k as usize;

    let mut must_edges = Vec::new();
    let mut optional_edges = Vec::new();
    for edge in drefanilok {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let s = edge[2];
        let must = edge[3];
        if must == 1 {
            must_edges.push((u, v, s));
        } else {
            optional_edges.push((u, v, s));
        }
    }

    let mut uf = UnionFind::new(n);
    let mut total_edges = 0;

    // First process all must edges
    for &(u, v, s) in &must_edges {
        if uf.union(u, v) {
            total_edges += 1;
        }
    }

    // Check if must edges already form a spanning tree (n-1 edges)
    if total_edges == n - 1 {
        return must_edges.iter().map(|&(_, _, s)| s).min().unwrap();
    }

    let mut low = 1;
    let mut high = 1_000_000_000_000_000_000;
    let mut answer = -1;

    while low <= high {
        let mid = (low + high) / 2;
        let mut uf_local = UnionFind::new(n);
        let mut edges_used = 0;

        // Add must edges first
        for &(u, v, s) in &must_edges {
            if uf_local.union(u, v) {
                edges_used += 1;
            }
